footer p {
  font-size: 0.875rem;
  color: var(--muted);
}

@media (max-width: 600px) {
  .footer-inner {
    flex-direction: column;
    text-align: center;
  }

  .hero {
    padding: 4rem 0 3.5rem;
  }
}
